### 参考答案

**1. RAII 风格 GPIO 控制器**

```cpp
// gpio_controller.h
#include <string>
#include <stdexcept>
#include <fstream>
#include <iostream>

class GPIOController {
public:
    enum class Direction { INPUT, OUTPUT };

    // 构造: 初始化 GPIO 引脚
    GPIOController(int pin, Direction dir) : pin_(pin) {
        // 导出引脚
        std::ofstream export_file("/sys/class/gpio/export");
        if (!export_file) throw std::runtime_error("Cannot export GPIO");
        export_file << pin;

        // 设置方向
        std::string dir_path = "/sys/class/gpio/gpio" + std::to_string(pin) + "/direction";
        std::ofstream dir_file(dir_path);
        dir_file << (dir == Direction::OUTPUT ? "out" : "in");

        // 打开值文件
        std::string val_path = "/sys/class/gpio/gpio" + std::to_string(pin) + "/value";
        value_file_.open(val_path);

        std::cout << "GPIO " << pin << " initialized" << std::endl;
    }

    // 析构: 自动释放引脚
    ~GPIOController() {
        value_file_.close();
        std::ofstream unexport("/sys/class/gpio/unexport");
        unexport << pin_;
        std::cout << "GPIO " << pin_ << " released" << std::endl;
    }

    void write(bool high) {
        value_file_ << (high ? "1" : "0") << std::flush;
    }

    // 禁止拷贝
    GPIOController(const GPIOController&) = delete;
    GPIOController& operator=(const GPIOController&) = delete;

private:
    int pin_;
    std::fstream value_file_;
};

// 使用:
// {
//     GPIOController led(17, GPIOController::Direction::OUTPUT);
//     led.write(true);   // LED 亮
//     led.write(false);  // LED 灭
// }  // 自动释放 GPIO 17
```

**2. Rule of Five 串口连接类**

```cpp
#include <string>
#include <iostream>
#include <utility>

class SerialPort {
public:
    // 构造
    explicit SerialPort(const std::string& port, int baud = 115200)
        : port_name_(port), baud_(baud), fd_(-1) {
        // fd_ = open(port.c_str(), O_RDWR | O_NOCTTY);
        fd_ = 42;  // 模拟
        std::cout << "Opened " << port << " @" << baud << std::endl;
    }

    // 1. 析构
    ~SerialPort() {
        if (fd_ >= 0) {
            // close(fd_);
            std::cout << "Closed " << port_name_ << std::endl;
        }
    }

    // 2. 拷贝构造 (禁止: 串口不能复制)
    SerialPort(const SerialPort&) = delete;

    // 3. 拷贝赋值 (禁止)
    SerialPort& operator=(const SerialPort&) = delete;

    // 4. 移动构造
    SerialPort(SerialPort&& other) noexcept
        : port_name_(std::move(other.port_name_)),
          baud_(other.baud_), fd_(other.fd_) {
        other.fd_ = -1;  // 原对象放弃所有权
    }

    // 5. 移动赋值
    SerialPort& operator=(SerialPort&& other) noexcept {
        if (this != &other) {
            if (fd_ >= 0) { /* close(fd_); */ }  // 先关闭自己的
            port_name_ = std::move(other.port_name_);
            baud_ = other.baud_;
            fd_ = other.fd_;
            other.fd_ = -1;
        }
        return *this;
    }

private:
    std::string port_name_;
    int baud_;
    int fd_;
};

// 使用:
// SerialPort port1("/dev/ttyUSB0");
// SerialPort port2 = std::move(port1);  // 移动: port1 不再有效
```

**3. Move 语义优化**

```cpp
#include <vector>
#include <iostream>
#include <chrono>

std::vector<double> generate_trajectory(int n_points) {
    std::vector<double> traj(n_points);
    for (int i = 0; i < n_points; ++i) {
        traj[i] = static_cast<double>(i) / n_points;
    }
    return traj;  // C++11 NRVO: 编译器自动优化, 不会复制
}

void process_trajectory(std::vector<double>&& traj) {
    // 接收右值引用: 直接"偷"数据, 零拷贝
    std::cout << "处理 " << traj.size() << " 个轨迹点" << std::endl;
}

// 使用:
// auto traj = generate_trajectory(1000000);  // NRVO, 无拷贝
// process_trajectory(std::move(traj));       // 移动语义, 无拷贝
// traj 现在是空的
```
